final:
module top_module(ledIn, obf_ledGreen, ledRed);input [3:0] ledIn;
  output obf_ledGreen, ledRed;
  reg obf_ledGreen, ledRed;

  always @ (ledIn)
  begin
    if(ledIn == 4'b1111)
      begin
	obf_ledGreen  = 1;
	ledRed = 0;
      end
    else
      begin
	obf_ledGreen  = 0;
	ledRed = 1;
      end
  end

endmodule
